// flutter pub add get_itimport 'package:bookly/Feature/Books/data/repositories/similar_books_repo.dart';import 'package:bookly/Feature/Books/domain/repositories/similar_books_repo_impl.dart';import 'package:bookly/Feature/Books/domain/use_cases/similar_books_use_case.dart';import 'package:bookly/Feature/Home/data/repositories/home_repo.dart';import 'package:bookly/Feature/Home/domain/repositories/home_repo_imple.dart';import 'package:get_it/get_it.dart';import '../../Feature/Home/domain/use_cases/home_use_cases.dart';final GetIt getIt = GetIt.instance;void setupService() {  getIt.registerLazySingleton<HomeRepo>(() => HomeRepoImpl());  getIt.registerLazySingleton<SimilarBooksRepo>(() => SimilarBooksRepoImpl());  //------------------------------------------------------------------  getIt.registerLazySingleton<FetchBooksPicturesUseCase>(      () => FetchBooksPicturesUseCase(getIt<HomeRepo>()));  getIt.registerLazySingleton<FetchAllBooksUseCase>(      () => FetchAllBooksUseCase(getIt<HomeRepo>()));  ////////////////////////////////////////////////////  getIt.registerLazySingleton<SimilarBooksUseCase>(      () => SimilarBooksUseCase(getIt<SimilarBooksRepo>()));}